// -- Settings Mapping --
export function mapSettings(raw: any): any {
  const result: any = {};
  if (Array.isArray(raw)) {
    for (const entry of raw) {
      const key = entry.setting_key ?? entry.key ?? "";
      const valueObj = entry.setting_value ?? entry.value ?? {};
      result[key] = valueObj.value ?? valueObj ?? "";
    }
  }
  return result;
}

